import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Base item premiums (with first-insurance +10%, +5G fee, new customer 0 years)
  it.todo("quotes a single sword for a new customer");
  it.todo("quotes a single amulet for a new customer");
  it.todo("quotes a single staff for a new customer");
  it.todo("quotes a single potion for a new customer");
  it.todo("quotes a single rune component for a new customer");

  // Multiple items
  it.todo("quotes multiple distinct items by summing their base premiums");
  it.todo("quotes three alike components as a building block at 60G base");
  it.todo("quotes four alike components as one block (60G) plus one single (25G)");

  // Modifiers on items
  it.todo("adds 50% surcharge for cursed items");
  it.todo("adds 30% surcharge for enchantment level >= 5");

  // Customer-level modifiers
  it.todo("applies 20% loyalty discount for customers with >= 2 years");
  it.todo("applies 15% discount on contracts after the first");

  // Rounding in MHPCO favor (up)
  it.todo("rounds the final premium up to whole G");

  // Claims
  it.todo("processes a basic claim with 100G deductible");
  it.todo("reimburses 50% for damage to items with enchantment >= 8");
  it.todo("fully reimburses damage to items made of dragon material");
  it.todo("caps total payout at twice the insurance sum across claims");
});

