type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const MAIN_ITEM_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const isComponent = (item: Item): boolean =>
  MAIN_ITEM_PREMIUM[item.type] === undefined;

const computeBasePremium = (items: Item[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += MAIN_ITEM_PREMIUM[item.type];
    }
  }
  for (const count of Object.values(componentCounts)) {
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const leftover = count % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PREMIUM + leftover * COMPONENT_PREMIUM;
  }
  return total;
};

const applyPercent = (amount: number, percent: number): number =>
  Math.ceil((amount * percent) / 100);

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    const base = computeBasePremium(step.items);
    const premium = applyPercent(base, 110) + 5;
    return { premium };
  });
  return { results };
};

