type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const MAIN_ITEM_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const isComponent = (item: Item): boolean =>
  MAIN_ITEM_PREMIUM[item.type] === undefined;

// Returns the per-item base premium share for each input item (same length/order).
// Components are grouped by type: each group of 3 alike is priced at 60 G total
// (20 G per component), with leftovers at 25 G each.
const itemBasePremiums = (items: Item[]): number[] => {
  const componentIndices: Record<string, number[]> = {};
  const shares = new Array<number>(items.length).fill(0);
  items.forEach((item, idx) => {
    if (isComponent(item)) {
      (componentIndices[item.type] ??= []).push(idx);
    } else {
      shares[idx] = MAIN_ITEM_PREMIUM[item.type];
    }
  });
  for (const indices of Object.values(componentIndices)) {
    const blocks = Math.floor(indices.length / COMPONENT_BLOCK_SIZE);
    const blocked = blocks * COMPONENT_BLOCK_SIZE;
    const blockShare = COMPONENT_BLOCK_PREMIUM / COMPONENT_BLOCK_SIZE; // 20
    indices.forEach((idx, i) => {
      shares[idx] = i < blocked ? blockShare : COMPONENT_PREMIUM;
    });
  }
  return shares;
};

const itemPremium = (item: Item, base: number): number => {
  let premium = base;
  if (item.cursed) premium = (premium * 150) / 100;
  return premium;
};

const applyPercent = (amount: number, percent: number): number =>
  Math.ceil((amount * percent) / 100);

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    const bases = itemBasePremiums(step.items);
    const subtotal = step.items.reduce(
      (sum, item, i) => sum + itemPremium(item, bases[i]),
      0,
    );
    const premium = applyPercent(subtotal, 110) + 5;
    return { premium };
  });
  return { results };
};

