const reimbursableFor = (policy: Policy, damage: Damage): number => {
  const item = policy.items.find((it) => it.type === damage.itemType);
  if (item && item.enchantment >= 8) return damage.amount / 2;
  return damage.amount;
};

const processClaim = (policy: Policy, damages: Damage[]): ClaimResult => {
  const covered = damages.reduce(
    (sum, d) => sum + reimbursableFor(policy, d),
    0,
  );
  const afterDeductible = Math.max(0, covered - DEDUCTIBLE);
  const payout = Math.min(Math.floor(afterDeductible), policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

